/**
 *
 * @namespace Console
 *
 */

const _ = require('lodash');
const JQ_BROWSER = require('jquery.browser');

const CONSOLE = {
    "prop": {
        "warn": _propWarn,
        "error": _propError,
        "throw": _propThrow
    }
};

/**
 *
 * @namespace MESSAGES
 *
 */
const MESSAGES = {};

/**
 *
 * @namespace MESSAGES.prop
 *
 */
// 프로퍼티 관련 메시지 객체
MESSAGES.prop = _.assign({}, {

    "all": '타입이 유효하지 않거나, 값이 존재하지 않습니다.',
    "type": '타입이 유효하지 않습니다.',
    "value": '값이 존재하지 않습니다.',
    "deprecatedParameter": ' 파라메터는 현재 버전에서 @deprecated 되었습니다.',
    "deprecatedProperty": ' 프로퍼티는 현재 버전에서 @deprecated 되었습니다.',
    "deprecatedMethod": ' 메서드는 현재 버전에서 @deprecated 되었습니다.',
    "empty": ''
});

/**
 *
 * @param {Function|String} constructor - 생성자 함수 또는 이름
 * @param {String} msg - msg
 * @param {String} msgType - msgType
 *
 * @return {object} BXUI.Console.prop 객체
 *
 * @memberof BXUI.Console.prop
 *
 */
function _propWarn(constructor = null, msg = '', msgType = 'empty'){

    console.warn(`${_getConsoleMsg(constructor, msg, msgType)}`);

    return this;
}

/**
 *
 * @param {Function|String} constructor - 생성자 함수 또는 이름
 * @param {String} msg - msg
 * @param {String} msgType - msgType
 *
 * @return {object} BXUI.Console.prop 객체
 *
 * @memberof BXUI.Console.prop
 */
function _propError(constructor = null, msg = '', msgType = 'empty'){

    console.error(`${_getConsoleMsg(constructor, msg, msgType)}`);

    return this;
}

/**
 *
 * @param {Function|String} constructor - 생성자 함수 또는 이름
 * @param {String} propertyName - 프로퍼티명
 * @param {String} type - log 타입
 *
 * @return {object} BXUI.Console.prop 객체
 *
 * @memberof BXUI.Console.prop
 */
function _propThrow(constructor = null, msg = '', msgType = 'empty'){

    throw new Error(`${_getConsoleMsg(constructor, msg, msgType)}`);
}

/**
 *
 * @param {Function|String} constructor - 생성자 함수 또는 이름
 * @param {String} propertyName - 프로퍼티명
 * @param {String} type - log 타입
 *
 * @return {object} BXUI.Console.prop 객체
 *
 * @memberof BXUI.Console.prop
 *
 */
function _getConsoleMsg(constructor = null, msg = '', msgType = 'empty'){

    let allTypeMsg = MESSAGES.prop['all'];

    if (!_.isFunction(constructor) && !_.isString(constructor)){
        throw new Error(`constructor ${allTypeMsg}`);
    }

    if (!_.isString(msg) || msg === ''){
        throw new Error(`msg ${allTypeMsg}`);
    }

    if (!_.isString(msgType) || _.trim(msgType).length === 0){
        throw new Error(`msgType ${allTypeMsg}`);
    }

    let constructorName = '';
    let {name, version, platform} = JQ_BROWSER;

    if (_.isFunction(constructor)){
        constructorName = constructor.name || constructor.componentName;
    }
    else if (_.isString(constructor)){
        constructorName = constructor;
    }

    let msgs = [];
    msgs.push(`[${constructorName}] ${msg} ${MESSAGES.prop[msgType]}`);

    // BX-UI 내부 Component 일 경우
    if (_.isFunction(constructor) && constructor.componentName){
        msgs.push(`(http://bwg.co.kr/bxui/bx-ui/doc/${constructor.componentName}.html)`);
    }

    msgs.push(`\n\n\n name: ${name}`);
    msgs.push(`\n version: ${version}`);
    msgs.push(`\n platform: ${platform}`);

    return msgs.join('');
}


module.exports = CONSOLE;
